package com.metalworkshop.PatientService.controller;import com.metalworkshop.PatientService.dto.PatientCreateRequestDto;import com.metalworkshop.PatientService.dto.PatientResponseDto;import com.metalworkshop.PatientService.dto.PatientUpdateRequestDto;import com.metalworkshop.PatientService.dto.validators.ValidUUID;import com.metalworkshop.PatientService.service.PatientService;import io.swagger.v3.oas.annotations.Operation;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.groups.Default;import org.springframework.data.domain.Page;import org.springframework.http.HttpHeaders;import org.springframework.http.ResponseEntity;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import java.net.URI;import java.util.Optional;import java.util.UUID;@RestController@RequestMapping("/patients")@Tag(name = "Patient", description = "API for managing Patients")public class PatientController {    private final PatientService patientService;    public PatientController(PatientService patientService) {        this.patientService = patientService;    }    @GetMapping    @Operation(summary = "Get Patients")    public ResponseEntity<Page<PatientResponseDto>> findAll(            @RequestParam(defaultValue = "0") int page,            @RequestParam(defaultValue = "20") int size,            @RequestParam(required = false) String name) {        Page<PatientResponseDto> response = patientService.findAllPageable(page, size, name);        HttpHeaders headers = new HttpHeaders();        headers.add("X-Page-Number", String.valueOf(response.getNumber()));        headers.add("X-Page-Size", String.valueOf(response.getSize()));        return ResponseEntity.ok()                .headers(headers)                .body(response);    }    @GetMapping("/{id}")    @Operation(summary = "Get Patient by id")    public ResponseEntity<PatientResponseDto> findById(            @ValidUUID @PathVariable() UUID id) {        Optional<PatientResponseDto> patientFound = patientService.findById(id);        return ResponseEntity.of(patientFound);    }    @PostMapping    @Operation(summary = "Create a new Patient")    public ResponseEntity<PatientResponseDto> createPatient(            @Validated(Default.class) @RequestBody PatientCreateRequestDto requestDto) {        PatientResponseDto newPatient = patientService.createPatient(requestDto);        return ResponseEntity                .created(URI.create("/patients/" + newPatient.getId()))                .body(newPatient);    }    @PutMapping("/{id}")    @Operation(summary = "Update a Patient")    public ResponseEntity<PatientResponseDto> updatePatient(            @ValidUUID @PathVariable() UUID id,            @Validated(Default.class) @RequestBody PatientUpdateRequestDto requestDto) {        PatientResponseDto patientResponseDto = patientService.updatePatient(id, requestDto);        return ResponseEntity.ok().body(patientResponseDto);    }    @DeleteMapping("/{id}")    @Operation(summary = "Delete a new Patient")    public ResponseEntity<Void> deletePatientById(            @ValidUUID @PathVariable() UUID id) {        patientService.deleteByUUID(id);        return ResponseEntity.noContent().build();    }}